const message = $json.message;

if (!message) return [];

// Aceita voice (gravação no app), audio (arquivo enviado) ou document
const tipos = ['voice', 'audio', 'document'];
let arquivo = null;
let mimeType = 'audio/ogg';

for (const tipo of tipos) {
  if (message[tipo]) {
    arquivo = message[tipo];
    mimeType = arquivo.mime_type || (tipo === 'voice' ? 'audio/ogg' : 'audio/mpeg');
    break;
  }
}

// Se não for áudio, ignora silenciosamente (ex: mensagem de texto)
if (!arquivo) return [];

return [{
  json: {
    file_id: arquivo.file_id,
    mime_type: mimeType,
    chat_id: String(message.chat.id),
    data_hora: new Date(message.date * 1000).toISOString()
  }
}];

const items = $input.all();
const mimeType = $('Extrair Arquivo de Áudio').item.json.mime_type || 'audio/ogg';

let ext = 'oga';
if (mimeType.includes('mpeg') || mimeType.includes('mp3')) ext = 'mp3';
else if (mimeType.includes('m4a') || mimeType.includes('mp4')) ext = 'm4a';
else if (mimeType.includes('wav')) ext = 'wav';
else if (mimeType.includes('webm')) ext = 'webm';

for (const item of items) {
  if (item.binary && item.binary.data) {
    item.binary.data.fileName = `audio.${ext}`;
    item.binary.data.mimeType = mimeType;
    item.binary.data.fileExtension = ext;
  }
}

return items;

