const chatId = $('Extrair Arquivo de Áudio').item.json.chat_id;
const mensagem = $('Formatar Mensagem Final').item.json.mensagem_completa;

function dividir(texto, limite) {
  const partes = [];
  let atual = '';
  for (const linha of texto.split('\n')) {
    if ((atual + '\n' + linha).length > limite) {
      if (atual) partes.push(atual.trim());
      atual = linha;
    } else {
      atual = atual ? atual + '\n' + linha : linha;
    }
  }
  if (atual.trim()) partes.push(atual.trim());
  return partes;
}

const partes = dividir(mensagem, 4000);

return partes.map((p, i) => ({
  json: {
    chat_id: chatId,
    text: partes.length > 1 ? `📄 Parte ${i+1}/${partes.length}\n\n${p}` : p
  }
}));

const texto = $('Formatar Mensagem Final').item.json.mensagem_completa;

const limpo = texto
  .replace(/^### (.+)$/gm, '$1')
  .replace(/^## (.+)$/gm, '$1')
  .replace(/^# (.+)$/gm, '$1')
  .replace(/\*\*(.+?)\*\*/g, '$1')
  .replace(/^---+$/gm, '');

return [{ json: { conteudo: limpo } }];
